import React, { useState } from 'react';
import Sidebar from './Sidebar';
import Topbar from './Topbar';
import './index.css';

const CRYSTAL_TYPES = ['All', 'Calcium Oxalate', 'Uric Acid', 'Struvite', 'Ca Phosphate', 'Cystine'];

const CRYSTAL_COLORS = {
  'Calcium Oxalate': '#E24B4A',
  'Uric Acid':       '#F5A623',
  'Struvite':        '#1FB505',
  'Ca Phosphate':    '#6D9922',
  'Cystine':         '#9B59B6',
};

const RISK_STYLE = {
  High:     { background: '#FFF0ED', color: '#A32D2D' },
  Moderate: { background: '#FFF8ED', color: '#C07320' },
  Low:      { background: '#E8F5E8', color: '#1F5330' },
};

const CrystalShape = ({ type }) => {
  const color = CRYSTAL_COLORS[type] || '#888';
  const shapes = {
    'Calcium Oxalate': (
      <svg width="36" height="36" viewBox="0 0 36 36" fill="none">
        <polygon points="18,3 30,10 30,26 18,33 6,26 6,10" stroke={color} strokeWidth="1.5" fill={color + '22'} />
        <line x1="18" y1="3" x2="18" y2="33" stroke={color} strokeWidth="1" />
        <line x1="6" y1="18" x2="30" y2="18" stroke={color} strokeWidth="1" />
      </svg>
    ),
    'Uric Acid': (
      <svg width="36" height="36" viewBox="0 0 36 36" fill="none">
        <circle cx="18" cy="18" r="13" stroke={color} strokeWidth="1.5" fill={color + '22'} />
        <line x1="18" y1="5" x2="18" y2="31" stroke={color} strokeWidth="1" />
        <line x1="5" y1="18" x2="31" y2="18" stroke={color} strokeWidth="1" />
        <line x1="9" y1="9" x2="27" y2="27" stroke={color} strokeWidth="1" />
        <line x1="27" y1="9" x2="9" y2="27" stroke={color} strokeWidth="1" />
      </svg>
    ),
    'Struvite': (
      <svg width="36" height="36" viewBox="0 0 36 36" fill="none">
        <rect x="6" y="6" width="24" height="24" rx="3" stroke={color} strokeWidth="1.5" fill={color + '22'} />
        <line x1="18" y1="6" x2="18" y2="30" stroke={color} strokeWidth="1" />
        <line x1="6" y1="18" x2="30" y2="18" stroke={color} strokeWidth="1" />
      </svg>
    ),
    'Ca Phosphate': (
      <svg width="36" height="36" viewBox="0 0 36 36" fill="none">
        <polygon points="18,4 32,28 4,28" stroke={color} strokeWidth="1.5" fill={color + '22'} />
        <line x1="18" y1="4" x2="18" y2="28" stroke={color} strokeWidth="1" />
        <line x1="4" y1="28" x2="32" y2="28" stroke={color} strokeWidth="1" />
      </svg>
    ),
    'Cystine': (
      <svg width="36" height="36" viewBox="0 0 36 36" fill="none">
        <polygon points="18,4 32,18 18,32 4,18" stroke={color} strokeWidth="1.5" fill={color + '22'} />
        <line x1="4" y1="18" x2="32" y2="18" stroke={color} strokeWidth="1" />
        <line x1="18" y1="4" x2="18" y2="32" stroke={color} strokeWidth="1" />
      </svg>
    ),
  };
  return shapes[type] || (
    <svg width="36" height="36" viewBox="0 0 36 36" fill="none">
      <circle cx="18" cy="18" r="13" stroke={color} strokeWidth="1.5" fill={color + '22'} />
    </svg>
  );
};

const styles = {
  app:        { display: 'flex', flexDirection: 'column', width: '100%', height: '100vh', background: '#EEF0E8', overflow: 'hidden' },
  body:       { flex: 1, display: 'grid', gridTemplateColumns: '210px 1fr', minHeight: 0, overflow: 'hidden' },
  main:       { display: 'flex', flexDirection: 'column', minHeight: 0, overflow: 'hidden', background: '#EEF0E8' },
  pane:       { flex: 1, display: 'flex', flexDirection: 'column', padding: '20px 28px', gap: '14px', minHeight: 0, overflowY: 'auto' },
  header:     { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  pageTitle:  { fontSize: '18px', fontWeight: 700, color: '#141514', fontFamily: "'Poppins', sans-serif" },
  entryCount: { fontSize: '12px', color: '#A4AAA4', fontFamily: "'Poppins', sans-serif" },
  filters:    { display: 'flex', gap: '8px', flexWrap: 'wrap' },
  pill:       { padding: '6px 16px', borderRadius: '100px', border: '1.5px solid #D8DAD0', background: '#fff', fontSize: '12px', fontWeight: 500, cursor: 'pointer', fontFamily: "'Poppins', sans-serif", transition: 'all 0.15s' },
  pillActive: { background: '#1F5330', color: '#fff', borderColor: '#1F5330' },
  grid:       { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '14px' },
  card:       { background: '#fff', border: '1px solid #D8DAD0', borderRadius: '14px', overflow: 'hidden', transition: 'transform 0.15s, box-shadow 0.15s', cursor: 'default' },
  cardHover:  { transform: 'translateY(-4px)', boxShadow: '0 8px 24px rgba(0,0,0,0.10)' },
  cardVisual: { height: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  cardBody:   { padding: '12px 14px', display: 'flex', flexDirection: 'column', gap: '7px' },
  cardRow:    { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  cardType:   { fontSize: '12px', fontWeight: 700, color: '#141514', fontFamily: "'Poppins', sans-serif" },
  riskBadge:  { fontSize: '10px', fontWeight: 600, padding: '3px 9px', borderRadius: '12px', fontFamily: "'Poppins', sans-serif" },
  divider:    { borderTop: '1px solid #EEEFE8' },
  countBig:   { fontSize: '22px', fontWeight: 800, color: '#1F5330', fontFamily: "'Poppins', sans-serif" },
  countLabel: { fontSize: '10px', color: '#A4AAA4', fontFamily: "'Poppins', sans-serif" },
  metaLabel:  { fontSize: '10px', color: '#A4AAA4', fontFamily: "'Poppins', sans-serif" },
  metaValue:  { fontSize: '11px', fontWeight: 600, color: '#141514', fontFamily: "'Poppins', sans-serif" },
  emptyState: { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', flex: 1, color: '#A4AAA4', fontFamily: "'Poppins', sans-serif", gap: '8px' },
  emptyIcon:  { fontSize: '40px' },
  emptyText:  { fontSize: '14px', fontWeight: 500 },
  emptyHint:  { fontSize: '12px', color: '#C9CAC0' },
};

export default function CrystalLibrary({ goToLogin, goToUpload, goToResults, goToAnalysis, goToExport, goToPatients, goToLibrary, crystalRecords = [] }) {
  const [activeFilter, setActiveFilter] = useState('All');
  const [hoveredCard, setHoveredCard] = useState(null);

  const filtered = activeFilter === 'All'
    ? crystalRecords
    : crystalRecords.filter(c => c.crystalType === activeFilter);

  return (
    <div style={styles.app}>
      <Topbar goToLogin={goToLogin} />
      <div style={styles.body}>
        <Sidebar
          currentPage="library"
          goToUpload={goToUpload}
          goToResults={goToResults}
          goToAnalysis={goToAnalysis}
          goToExport={goToExport}
          goToPatients={goToPatients}
          goToLibrary={goToLibrary}
        />
        <div style={styles.main}>
          <div style={styles.pane}>

            {/* Header */}
            <div style={styles.header}>
              <div style={styles.pageTitle}>Crystal Library</div>
              <div style={styles.entryCount}>{filtered.length} {filtered.length === 1 ? 'entry' : 'entries'}</div>
            </div>

            {/* Filter Pills */}
            <div style={styles.filters}>
              {CRYSTAL_TYPES.map(type => (
                <button
                  key={type}
                  style={{ ...styles.pill, ...(activeFilter === type ? styles.pillActive : {}) }}
                  onClick={() => setActiveFilter(type)}
                >
                  {type}
                </button>
              ))}
            </div>

            {/* Empty State */}
            {filtered.length === 0 ? (
              <div style={styles.emptyState}>
                <div style={styles.emptyIcon}>🔬</div>
                <div style={styles.emptyText}>No crystals found</div>
                <div style={styles.emptyHint}>
                  {activeFilter === 'All'
                    ? 'Analyze a sample to start building your library'
                    : `No ${activeFilter} crystals detected yet`}
                </div>
              </div>
            ) : (
              /* Crystal Grid */
              <div style={styles.grid}>
                {filtered.map((crystal, i) => {
                  const color = CRYSTAL_COLORS[crystal.crystalType] || '#888';
                  return (
                    <div
                      key={i}
                      style={{ ...styles.card, ...(hoveredCard === i ? styles.cardHover : {}) }}
                      onMouseEnter={() => setHoveredCard(i)}
                      onMouseLeave={() => setHoveredCard(null)}
                    >
                      {/* Visual */}
                      <div style={{ ...styles.cardVisual, background: color + '18' }}>
                        <CrystalShape type={crystal.crystalType} />
                      </div>

                      <div style={styles.cardBody}>
                        {/* Type + Risk */}
                        <div style={styles.cardRow}>
                          <div style={styles.cardType}>{crystal.crystalType}</div>
                          <span style={{ ...styles.riskBadge, ...RISK_STYLE[crystal.risk] }}>
                            {crystal.risk}
                          </span>
                        </div>

                        <div style={styles.divider} />

                        {/* Count */}
                        <div>
                          <div style={styles.countBig}>{crystal.count}</div>
                          <div style={styles.countLabel}>crystals detected</div>
                        </div>

                        <div style={styles.divider} />

                        {/* Meta */}
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                          <div style={styles.cardRow}>
                            <span style={styles.metaLabel}>Sample ID</span>
                            <span style={{ ...styles.metaValue, color: '#1F5330' }}>{crystal.sampleId}</span>
                          </div>
                          <div style={styles.cardRow}>
                            <span style={styles.metaLabel}>Patient</span>
                            <span style={styles.metaValue}>{crystal.patientName}</span>
                          </div>
                          <div style={styles.cardRow}>
                            <span style={styles.metaLabel}>Date detected</span>
                            <span style={styles.metaValue}>
                              {new Date(crystal.date).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' })}
                            </span>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
